On amd64 platforms (tested with 6.2 and 7.0).
gmtime from libc doesn't returns to program if called with arg < -33884019326476800
May be we should return NULL?

How-To-Repeat: Simple program to test... first call return, second - loop forever...

#include <time.h>
#include <stdio.h>

void test(time_t t) {
    struct tm *date;
    printf("try %ld\n",t);
    date = gmtime(&t);
    printf(" ok\n");
}

int main(void) {
    time_t time_ok = -33884019326476800LL;
    time_t time_err = -33884019326476801LL;
    test(time_ok);
    test(time_err);
    return 0;
}
